// Local file copy into public_html -- derived + web assets ONLY.
// Master set never leaves Working (A9/A15 non-negotiable). Uses
// fs.copyFileSync, same discipline as Derive Tier Packages (05) --
// no large buffers held in node memory.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const derivedRoot = path.join('Working', prefix, 'derived');
const webDestRoot = path.join('public_html', 'files', prefix);

function copyTree(src, dest) {
  fs.mkdirSync(dest, { recursive: true });
  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
    const s = path.join(src, entry.name);
    const d = path.join(dest, entry.name);
    if (entry.isDirectory()) copyTree(s, d);
    else fs.copyFileSync(s, d);
  }
}

copyTree(derivedRoot, webDestRoot);

// Explicit guard, not just a convention -- refuse to proceed if
// anything under master_set/ is about to be copied.
const masterSetPath = path.join('Working', prefix, 'master_set');
if (webDestRoot.includes('master_set') || fs.existsSync(path.join(webDestRoot, '..', 'master_set'))) {
  throw new Error('Deploy guard: refusing a copy path that could expose the master set.');
}

return [{ json: { project_prefix: prefix, deployed: true, deployed_at: new Date().toISOString() } }];
